from matplotlib import pyplot as pltimport numpy as npimport cv2from skimage import measurefrom skimage.segmentation import clear_borderpixels_to_um = 0.454img = cv2.imread("../data/Osteosarcoma_01.tif")img1 = cv2.cvtColor(img, cv2.COLOR_BGR2GRAY)imgb = img[:,:,0]plt.figure()plt.imshow(imgb)plt.title("Blue Channel")ret, thresh = cv2.threshold(    img1,    0,    255,    cv2.THRESH_BINARY + cv2.THRESH_OTSU)kernel = np.ones((3,3), np.uint8)opening = cv2.morphologyEx(    thresh,    cv2.MORPH_OPEN,    kernel,    iterations=1)opening = clear_border(opening)distance = cv2.distanceTransform(    opening,    cv2.DIST_L2,    3)ret2, thresh2 = cv2.threshold(    distance,    0.2 * distance.max(),    255,    0)sure_fg = np.uint8(thresh2)sure_bg = cv2.dilate(opening, kernel, iterations=1)unknown = cv2.subtract(sure_bg, sure_fg)ret3, markers = cv2.connectedComponents(sure_fg)markers = markers + 10markers[unknown == 255] = 0markers = markers.astype(np.int32)markers = cv2.watershed(img, markers)# Make a clean label image for measurementlabel_img = markers.copy()label_img[label_img == -1] = 0   # remove boundarylabel_img[label_img == 10] = 0   # remove backgroundclusters = measure.regionprops(    label_img,    intensity_image=img1)for obj in clusters:    label = obj.label    area = obj.area * pixels_to_um**2    equiv_diameter = obj.equivalent_diameter * pixels_to_um    orientation = obj.orientation * 57.2958    major_axis = obj.major_axis_length * pixels_to_um    minor_axis = obj.minor_axis_length * pixels_to_um    perimeter = obj.perimeter * pixels_to_um    min_intensity = obj.min_intensity    mean_intensity = obj.mean_intensity    max_intensity = obj.max_intensity    output_file.write(        f'{file},{label},{area},{equiv_diameter},{orientation},'        f'{major_axis},{minor_axis},{perimeter},'        f'{min_intensity},{mean_intensity},{max_intensity}\n'    )